outputs.patch.diff:
--- a/ds.sas
+++ b/ds.sas
@@ -45,7 +45,7 @@
     length STUDYID $20 DOMAIN $2 USUBJID $40 DSSEQ 8 
            DSTERM $200 DSDECOD $200 DSCAT $40 DSSCAT $40
            DSSTDTC $20 EPOCH $40 DISCONFL $1;
-    
+    retain DSSEQ;
     set ds_raw;
     by USUBJID DSSTDTC;

@@ -58,7 +58,7 @@
     DSTERM = DSTERM_RAW;
     DSDECOD = upcase(DSTERM);

-    DSCAT = 'DISPOSITION';
+    DSCAT = 'DISPOSITION TRIAL';
     DSSCAT = '';

     DSSTDTC = put(DSSTDT, is8601da.);
@@ -66,7 +66,7 @@
     EPOCH = EPOCH_RAW;

     * Derive discontinuation flag;
-    if DSDECOD = 'COMPLETED' then DISCONFL = 'N';
+    if DSDECOD in ('COMPLETED', 'COMPLETE') then DISCONFL = 'N';
     else DISCONFL = 'Y';

     if first.USUBJID then DSSEQ = 0;
